import sys
from collections import deque
from typing import List

class Solution:
    def updateMatrix(self, grid: List[List[int]]) -> List[List[int]]:
        m, n = len(grid), len(grid[0])
        res = [[0]*n for _ in range(m)]
        q = deque()
        for i in range(m):
            for j in range(n):
                if grid[i][j] == 1:
                    res[i][j] = 0
                    q.append((i, j))
                else:
                    res[i][j] = float('inf')
        dirs = [(1, 0), (-1, 0), (0, 1), (0, -1)]
        while q:
            x, y = q.popleft()
            for dx, dy in dirs:
                nx, ny = x + dx, y + dy
                if 0 <= nx < m and 0 <= ny < n and res[nx][ny] > res[x][y] + 1:
                    res[nx][ny] = res[x][y] + 1
                    q.append((nx, ny))
        return res

if __name__ == '__main__':
    it = iter(sys.stdin.read().split())
    try:
        m = int(next(it))
        grid = [list(map(int, [next(it) for _ in range(m)])) for _ in range(m)]
    except StopIteration:
        sys.exit(0)
    sol = Solution()
    ans = sol.updateMatrix(grid)
    print(m)
    for row in ans:
        print(' '.join(map(str, row)))

