#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<vector<int>> updateMatrix(vector<vector<int>>& grid) {
        int m = grid.size(), n = grid[0].size();
        vector<vector<int>> res(m, vector<int>(n, 0));
        queue<pair<int, int>> q;
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                if (grid[i][j] == 1) {
                    q.push({i, j});
                    res[i][j] = 0;
                } else {
                    res[i][j] = INT_MAX;
                }
            }
        }
        vector<pair<int, int>> dirs = {{1, 0}, {-1, 0}, {0, 1}, {0, -1}};
        while (!q.empty()) {
            int x = q.front().first, y = q.front().second; q.pop();
            for (auto& dir : dirs) {
                int nx = x + dir.first, ny = y + dir.second;
                if (0 <= nx && nx < m && 0 <= ny && ny < n && res[nx][ny] > res[x][y] + 1) {
                    res[nx][ny] = res[x][y] + 1;
                    q.push({nx, ny});
                }
            }
        }
        return res;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int m;
    cin >> m;
    vector<vector<int>> grid(m, vector<int>(m));
    for (int i = 0; i < m; i++) {
        for (int j = 0; j < m; j++) {
            cin >> grid[i][j];
        }
    }
    Solution sol;
    vector<vector<int>> ans = sol.updateMatrix(grid);
    cout << m << '\n';
    for (int i = 0; i < m; i++) {
        for (int j = 0; j < m; j++) {
            cout << ans[i][j] << (j == m - 1 ? '\n' : ' ');
        }
    }
    return 0;
}
